-- ═══════════════════════════════════════════════════════════════════════════
-- ADVOCIS — Family Law: Custody and Best Interest
-- ═══════════════════════════════════════════════════════════════════════════

-- Best Interest of the Child
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_057', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Fam. Code §§ 3020-3049 (Best Interest of the Child)', 'FC §§ 3020-3049', 'Best Interest of the Child — Custody Determination Factors', 'California custody law prioritizes the health, safety, and welfare of the child and frequent and continuing contact with both parents. Court must consider all relevant factors including history of abuse by either parent. Legislative policy: children benefit from frequent and continuing contact with both parents, and both parents share rights and responsibilities. DV history is a factor (§ 3020(a)).', '["Health, safety, and welfare of child is paramount (§ 3020)","Frequent and continuing contact with both parents preferred (§ 3020(b))","No preference based on sex of parent (§ 3040)","Court may consider habitual or continual illegal use of controlled substances (§ 3041.5)","Court must consider history of abuse by either parent (§ 3020(a))","Best interest considers: nature and amount of contact, age of child, parental stability","Court must state reasons for custody order if requested (§ 3048)","Friendly parent factor: willingness to facilitate contact with other parent","No presumption for or against joint or sole custody except DV (§ 3040)"]', '[{"section":"3020(a)","description":"Health, safety, welfare paramount; DV history as factor"},{"section":"3020(b)","description":"Frequent and continuing contact with both parents"},{"section":"3040","description":"Order of preference — both parents before third parties, no sex preference"},{"section":"3040(a)(1)","description":"Joint custody to both parents"},{"section":"3040(a)(2)","description":"Sole custody to either parent"},{"section":"3040(a)(3)","description":"Custody to other person — requires finding by clear and convincing evidence"},{"section":"3041.5","description":"Illegal drug use as factor"},{"section":"3048","description":"Statement of reasons for custody order on request"}]', '["custody_order","FL_300","FL_311","custody_declaration","best_interest_analysis","parenting_plan","visitation_schedule"]', '["family-law-custody-audit"]', 'California Family Courts', 1, 1, datetime('now'), datetime('now'));

-- DV Rebuttable Presumption
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_058', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Fam. Code § 3044 (DV Rebuttable Presumption Against Custody)', 'FC § 3044', 'Domestic Violence Rebuttable Presumption Against Custody', 'Creates rebuttable presumption that it is detrimental to the best interest of the child to award sole or joint physical or legal custody to a person who has perpetrated domestic violence within the previous 5 years. Perpetrator must overcome presumption by preponderance of evidence showing factors in § 3044(b). Finding of DV is required, not merely allegation.', '["Rebuttable presumption against custody to DV perpetrator","Applies to DV within previous 5 years","Finding of DV required — judicial finding, not mere allegation","Must be overcome by preponderance of evidence","Factors to overcome: completion of batterer treatment program, compliance with probation/parole, completion of substance abuse program, compliance with restraining orders, 12-step or domestic violence treatment program","Court must state reasons in writing or on the record if overcoming presumption","Applies to both physical and legal custody — sole and joint","Does not create presumption in favor of other parent — best interest still governs"]', '[{"section":"3044(a)","description":"Rebuttable presumption against DV perpetrator for custody"},{"section":"3044(b)","description":"Factors to overcome presumption — 7 considerations"},{"section":"3044(b)(1)","description":"Completion of batterer intervention program"},{"section":"3044(b)(2)","description":"Compliance with probation or parole terms"},{"section":"3044(b)(3)","description":"Compliance with restraining order terms"},{"section":"3044(b)(5)","description":"Best interest of the child"},{"section":"3044(c)","description":"Written or oral statement of reasons if presumption overcome"},{"section":"3044(d)","description":"Definition — perpetrated domestic violence as judicial finding"}]', '["DV_finding","custody_order","batterer_treatment_completion","restraining_order_compliance","FL_300","FL_312","custody_evaluation"]', '["family-law-custody-audit"]', 'California Family Courts', 1, 1, datetime('now'), datetime('now'));

-- Supervised Visitation
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_059', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Fam. Code §§ 3100-3105 (Supervised Visitation)', 'FC §§ 3100-3105', 'Supervised Visitation — Professional and Nonprofessional Monitors', 'Court may order supervised visitation when necessary to protect child. Professional monitors must meet Uniform Standards of Practice (FC § 3200.5). Court must consider nature of allegations, relationship between child and parent, and impact of supervision on child. Third-party professional supervised visitation providers must be registered with local court.', '["Court may order supervised visitation to protect child safety","Professional monitors must meet Uniform Standards (FC 3200.5)","Nonprofessional monitors selected by agreement or court order","Monitor must have no record of DV, child abuse, or substance abuse","Court must specify conditions: location, duration, cost allocation","Cost of supervision allocated between parties based on ability to pay","Report of any safety concerns required from monitor","Court must consider least restrictive means consistent with child safety","Grandparent or stepparent visitation subject to § 3100-3105"]', '[{"section":"3100","description":"Court authority to grant reasonable visitation"},{"section":"3100(a)","description":"Supervised visitation when necessary for child safety"},{"section":"3100(b)","description":"Grandparent/stepparent visitation rights"},{"section":"3102","description":"Visitation after death of custodial parent"},{"section":"3103","description":"Grandparent visitation when parents in dispute"},{"section":"3104","description":"Grandparent petition in certain circumstances"},{"section":"3105","description":"Court authority over visitation conditions"}]', '["visitation_order","supervised_visitation_order","monitor_report","FL_311","FL_341(d)","professional_monitor_registration","safety_concern_report"]', '["family-law-custody-audit"]', 'California Family Courts', 1, 1, datetime('now'), datetime('now'));

-- Custody Evaluation
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_060', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Fam. Code §§ 3110-3118 (Child Custody Evaluation)', 'FC §§ 3110-3118', 'Child Custody Evaluation — Court-Appointed and Private Evaluators', 'Court may appoint evaluator to investigate and report on custody or visitation issues. Evaluator must meet qualifications per CRC 5.220. Parties entitled to cross-examine evaluator at hearing. Report must include methodology, sources of information, and basis for recommendations. Evaluator must disclose potential bias and conflicts.', '["Court may appoint evaluator sua sponte or on motion","Evaluator must meet qualifications — CRC 5.220 (education, training, experience)","Must interview both parents, children, and relevant third parties","Must consider all relevant factors including DV history","Report must include methodology, sources, and basis for recommendations","Parties have right to cross-examine evaluator at hearing","Evaluator must disclose conflicts of interest and potential bias","Cost allocated between parties based on ability to pay","Report generally confidential but available to parties and counsel","Private evaluators (§ 3111) must meet same standards"]', '[{"section":"3110","description":"Court authority to appoint evaluator"},{"section":"3111","description":"Private child custody evaluator — qualifications"},{"section":"3111.5","description":"Domestic violence training requirements for evaluators"},{"section":"3112","description":"Court to consider report — not bound by recommendation"},{"section":"3113","description":"Confidentiality of evaluation and report"},{"section":"3116","description":"Evaluator must consider child safety first"},{"section":"3118","description":"Standards for evaluators — CRC 5.220"}]', '["custody_evaluation_report","evaluator_appointment_order","FL_327","cross_examination_of_evaluator","evaluator_qualifications","conflict_disclosure","CRC_5.220_compliance"]', '["family-law-custody-audit","fcs-child-custody-recommending-counselor-audit"]', 'California Family Courts', 1, 1, datetime('now'), datetime('now'));

-- Custody Mediation
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_061', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Fam. Code §§ 3160-3186 (Custody Mediation)', 'FC §§ 3160-3186', 'Mandatory Custody Mediation — Family Court Services', 'Mediation required before contested custody hearing. Each superior court maintains FCS (Family Court Services) or contracts for mediation. Mediator meets with both parents (separately if DV issues). Some counties are "recommending" (mediator files recommendation with court) and others are "non-recommending" (confidential). DV screening required.', '["Mandatory mediation before contested custody hearing (§ 3170)","Court may waive mediation for good cause (§ 3170(b))","Mediator must screen for DV at outset (§ 3181)","DV victim may meet separately from perpetrator (§ 3181(b))","Support person may attend with DV victim (§ 3181(c))","Recommending vs non-recommending counties — varies by local court","Mediator recommendations (if recommending county) filed with court","Parties may bring counsel to mediation in certain circumstances","Mediator has mandatory reporting duties for child abuse","Agreement reached in mediation must be approved by court"]', '[{"section":"3160","description":"Purpose — reduce acrimony, protect child best interests"},{"section":"3161","description":"Duties of mediator — impartial, focused on best interests"},{"section":"3170","description":"Mandatory mediation before contested custody hearing"},{"section":"3175","description":"Mediator recommendation — recommending counties"},{"section":"3177","description":"Separate meetings for DV cases"},{"section":"3181","description":"DV screening requirements"},{"section":"3182","description":"Referral to other services if agreement not reached"},{"section":"3186","description":"Privilege and confidentiality of mediation communications"}]', '["mediation_appointment","FCS_recommendation","custody_agreement","DV_screening_form","FL_300","mediation_declaration","mediator_recommendation_report"]', '["family-law-custody-audit","fcs-child-custody-recommending-counselor-audit"]', 'California Family Court Services', 0, 1, datetime('now'), datetime('now'));

-- UCCJEA
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_062', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Fam. Code §§ 3400-3465 (UCCJEA — Uniform Child Custody Jurisdiction and Enforcement Act)', 'FC §§ 3400-3465 / UCCJEA', 'UCCJEA — Jurisdiction for Child Custody Determinations', 'Determines which state has jurisdiction to make initial or modify custody determinations. Home state jurisdiction is primary basis: state where child lived with parent for 6 consecutive months before proceeding. Prevents forum shopping. Exclusive continuing jurisdiction remains in original state until all parties leave or court declines. Emergency jurisdiction for immediate protection.', '["Home state has priority jurisdiction — 6 months continuous residence (§ 3421(a)(1))","Significant connection jurisdiction if no home state (§ 3421(a)(2))","Exclusive continuing jurisdiction until all parties leave or court declines (§ 3422)","Temporary emergency jurisdiction to protect child or sibling (§ 3424)","Court must communicate with courts of other states before exercising jurisdiction (§ 3410)","Inconvenient forum — court may decline jurisdiction (§ 3427)","Unjustifiable conduct — court must decline jurisdiction if party engaged in misconduct (§ 3428)","UCCJEA declaration required in first custody pleading (§ 3409)","Enforcement of other state custody orders — registration procedure (§ 3444-3461)"]', '[{"section":"3421(a)(1)","description":"Home state jurisdiction — 6 months continuous residence"},{"section":"3421(a)(2)","description":"Significant connection jurisdiction"},{"section":"3422","description":"Exclusive continuing jurisdiction"},{"section":"3424","description":"Temporary emergency jurisdiction"},{"section":"3427","description":"Inconvenient forum — may decline"},{"section":"3428","description":"Unjustifiable conduct — must decline"},{"section":"3409","description":"UCCJEA declaration required in first pleading"},{"section":"3444-3461","description":"Registration and enforcement of out-of-state orders"}]', '["UCCJEA_declaration","FL_105","custody_petition","jurisdictional_motion","interstate_communication_order","registration_of_foreign_order","emergency_custody_petition"]', '["family-law-custody-audit"]', 'California Family Courts / Interstate Coordination', 1, 1, datetime('now'), datetime('now'));


-- ═══════════════════════════════════════════════════════════════════════════
-- ADVOCIS — Family Law: Financial and Support
