-- Community Property Division
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_063', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Fam. Code §§ 2550-2556 (Community Property Division)', 'FC §§ 2550-2556', 'Community Property Division — Equal Division Requirement', 'Court must divide community estate equally (§ 2550). May divide in kind or by assigning values and offsetting. Deliberate misappropriation triggers sanctions (§ 2602). Undisclosed assets may be awarded 100% to other spouse (§ 2556). Date of separation determines community vs separate property. Fiduciary duties continue until distribution.', '["Equal division of community estate required (§ 2550)","Court may divide in kind or by offsetting values","Deliberate misappropriation: court may add breach amount to other side (§ 2602)","Undisclosed community assets may be awarded 100% to other spouse (§ 2556)","Date of separation determines character of property (§ 70)","Quasi-community property divided same as community property (§ 2550)","Debts divided equally except where assignment would be unjust (§ 2551)","Education/training loans assigned to benefited spouse (§ 2641)","Personal injury awards to injured spouse unless justice requires otherwise (§ 2603)"]', '[{"section":"2550","description":"Equal division requirement — community and quasi-community"},{"section":"2551","description":"Characterization of liabilities — equal assignment"},{"section":"2552","description":"Valuation date — trial or agreement"},{"section":"2553","description":"Division by referee or expert"},{"section":"2555","description":"Bifurcation — reserve jurisdiction over property"},{"section":"2556","description":"Undisclosed assets — penalty of 100% to other spouse"},{"section":"2602","description":"Deliberate misappropriation — breach remedies"},{"section":"2603","description":"Personal injury award disposition"}]', '["FL_142","FL_150","FL_160","property_declaration","QDRO","pension_division","judgment","asset_disclosure"]', '["family-law-custody-audit"]', 'California Family Courts', 1, 1, datetime('now'), datetime('now'));

-- Child Support Guidelines
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_064', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Fam. Code §§ 4050-4076 (Child Support Guidelines)', 'FC §§ 4050-4076', 'California Guideline Child Support — Algebraic Formula', 'Mandatory statewide guideline formula: CS = K[HN - (H%)(TN)]. K factor based on custodial time; HN = high earner net disposable income; TN = total net disposable income. Presumptively correct amount. May deviate only on specific findings on the record. Income includes all sources: salary, commissions, bonuses, rental, investment, social security.', '["Guideline formula: CS = K[HN - (H%)(TN)] (§ 4055)","K = 1 + H% (if H% < 50%) or 2 - 2(H%) (if H% > 50%)","Net disposable income includes all sources of income (§ 4058)","Deductions: taxes, mandatory retirement, health insurance, union dues, hardship (§ 4059)","Guideline amount is presumptively correct (§ 4057)","Deviation only on specific findings — written or on record (§ 4056)","Both parents obligated to support (§ 4053(e))","Income from new spouse not considered (§ 4057.5)","Add-on expenses: childcare for employment, health insurance, education, travel (§ 4062)","Court may impute income if parent voluntarily unemployed/underemployed (§ 4058(b))"]', '[{"section":"4050","description":"Legislative intent — adequate support, both parents share"},{"section":"4053","description":"Principles — both parents responsible, guideline presumptively correct"},{"section":"4055","description":"Guideline formula — algebraic calculation"},{"section":"4056","description":"Deviation — specific findings required on record"},{"section":"4057","description":"Presumption — rebuttal only by § 4057(b) factors"},{"section":"4058","description":"Income defined — all sources"},{"section":"4059-4060","description":"Deductions from gross income"},{"section":"4062","description":"Add-on expenses — childcare, health, education, travel"}]', '["FL_150","FL_155","FL_342","child_support_order","DissoMaster_printout","income_and_expense_declaration","W2_tax_returns","support_modification"]', '["family-law-custody-audit"]', 'California Family Courts / DCSS', 1, 1, datetime('now'), datetime('now'));

-- Fiduciary Duties in Dissolution
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_065', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Fam. Code §§ 721, 1100, 2100-2113 (Fiduciary Duties in Marriage/Dissolution)', 'FC §§ 721/1100/2100-2113', 'Fiduciary Duties Between Spouses — During Marriage and Dissolution', 'Spouses owe each other fiduciary duties of highest good faith and fair dealing — same as business partners. Duty continues through dissolution until final distribution. Includes duty of full disclosure of all assets, debts, income, and expenses. Breach remedies include sanctions under § 271, asset penalty under § 2107, and tort damages. Automatic Temporary Restraining Orders (ATROs) preserve status quo.', '["Spouses owe fiduciary duties of highest good faith — same as business partners (§ 721)","Duty of full disclosure of all community and separate property (§ 2100)","Preliminary Declaration of Disclosure required (§ 2104) — FL-140/FL-142","Final Declaration of Disclosure required (§ 2105) — FL-141","Cannot transfer, encumber, conceal, or dispose of community property without consent (§ 1100)","ATROs: automatic restraining orders preventing asset dissipation (§ 2040)","Breach: court may award 50-100% of undisclosed asset to other spouse (§ 2107(d))","Sanctions under § 271 for breach of fiduciary duty or litigation misconduct","Duty continues until final distribution of community estate"]', '[{"section":"721(b)","description":"Fiduciary duties between spouses — highest good faith"},{"section":"1100(e)","description":"Written consent for disposition of community property"},{"section":"2100","description":"Duty of full disclosure in dissolution proceedings"},{"section":"2104","description":"Preliminary Declaration of Disclosure — FL-140"},{"section":"2105","description":"Final Declaration of Disclosure — FL-141"},{"section":"2107(d)","description":"Penalty for nondisclosure — 50-100% of undisclosed asset"},{"section":"2040","description":"ATROs — automatic temporary restraining orders"},{"section":"271","description":"Sanctions for breach of fiduciary duty or litigation misconduct"}]', '["FL_140","FL_141","FL_142","FL_150","ATRO_summons","asset_disclosure","breach_of_fiduciary_duty_motion","sanctions_motion"]', '["family-law-custody-audit"]', 'California Family Courts', 1, 1, datetime('now'), datetime('now'));

-- Sanctions for Litigation Misconduct
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_066', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Fam. Code § 271 (Sanctions for Litigation Misconduct)', 'FC § 271', 'Family Law Sanctions — Frustrating Settlement and Cooperation', 'Court may impose attorney fee sanctions against party or counsel who frustrates settlement or increases litigation costs through uncooperative conduct. Based on furtherance of policy favoring settlement and reduction of litigation costs. Amount may be full attorney fees of other side. Not limited to ability to pay — sanction may exceed ability. Conduct-based, not need-based.', '["Sanctions for conduct that frustrates settlement policy","Applies to party or attorney","Based on extent to which conduct frustrates cooperation","Amount: proportional to bad conduct, may include full attorney fees","Not limited by ability to pay — distinguishes from need-based fees","Court considers all circumstances including nature, persistence of bad conduct","May be imposed at any time during proceedings","Written findings required","Appeal available — abuse of discretion standard","Cannot be used punitively — must relate to settlement frustration"]', '[{"section":"271(a)","description":"Authority to award fees as sanction for frustrating settlement"},{"section":"271(b)","description":"Amount — based on incomes, assets, liabilities"},{"section":"271(c)","description":"Court order must be in writing with reasons stated"},{"section":"271(d)","description":"Sanction is enforceable as money judgment"}]', '["sanctions_motion","FC_271_brief","attorney_fee_declaration","order_on_sanctions","judgment","misconduct_evidence"]', '["family-law-custody-audit"]', 'California Family Courts', 1, 1, datetime('now'), datetime('now'));


-- ═══════════════════════════════════════════════════════════════════════════
-- ADVOCIS — CPS/Dependency: WIC 300 Series
