-- WIC 300 — Dependency Jurisdiction
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_067', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Welf. & Inst. Code § 300 (Dependency Jurisdiction)', 'WIC § 300', 'Juvenile Dependency Jurisdiction — Grounds for Court Intervention', 'Defines grounds for juvenile court dependency jurisdiction over children who have suffered or are at substantial risk of suffering serious physical harm. Eleven subdivisions covering neglect, physical abuse, sexual abuse, emotional abuse, and parental incapacity. Must prove by preponderance of evidence at jurisdictional hearing.', '["(a) Serious physical harm inflicted nonaccidentally by parent","(b) Failure to protect — serious physical harm or illness due to parent inability to supervise/protect","(c) Serious emotional damage — no parent willing to provide treatment","(d) Sexual abuse or at substantial risk of sexual abuse","(e) Severe physical abuse under age 5 — as defined in PC 11165.4","(f) Parent caused death of another child through abuse/neglect","(g) Sibling has been abused/neglected as defined in (a)-(j)","(h) Left without provision for support (abandonment)","(i) Cruelty — acts of cruelty by parent","(j) Substantial risk that child will be sexually abused — as defined in PC 11165.1","Proved by preponderance of evidence at jurisdictional hearing"]', '[{"section":"300(a)","description":"Serious physical harm — nonaccidental"},{"section":"300(b)(1)","description":"Failure to protect — neglect, inability to supervise"},{"section":"300(c)","description":"Serious emotional damage"},{"section":"300(d)","description":"Sexual abuse or risk thereof"},{"section":"300(e)","description":"Severe physical abuse — child under 5"},{"section":"300(f)","description":"Parent caused death of another child"},{"section":"300(g)","description":"Sibling abuse/neglect"},{"section":"300(h)","description":"Abandonment — left without provision"},{"section":"300(i)","description":"Cruelty by parent"},{"section":"300(j)","description":"Risk of sexual abuse"}]', '["dependency_petition","JV_100","jurisdictional_hearing_report","social_study","dispositional_report","CPS_referral"]', '["cps-dependency-family-reunification-audit"]', 'Juvenile Court / County CPS (DCFS)', 0, 1, datetime('now'), datetime('now'));

-- WIC 305 — Protective Custody
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_068', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Welf. & Inst. Code § 305 (Protective Custody Without Warrant)', 'WIC § 305', 'Protective Custody — Emergency Removal Without Warrant', 'Social worker or law enforcement may take child into temporary custody without warrant when reasonable cause to believe child is in immediate danger. Must immediately investigate, attempt to maintain child in home with services, and file petition within 48 hours if child is detained. Preference for placement with relative. Child must be released to parent unless continued danger.', '["May take temporary custody without warrant if immediate danger (§ 305)","Must immediately investigate and attempt services to keep child in home","Must release to parent unless continued danger","If detained, must file petition within 48 hours (§ 313)","Preference for placement with relative (§ 309)","Must make reasonable efforts to prevent removal (§ 306)","Must immediately notify parent of removal and rights","Must advise parent of right to counsel","Social worker must complete detention report for court","ICWA inquiry required if child may be Indian child (§ 224.2)"]', '[{"section":"305(a)","description":"Authority — peace officer or social worker may take temporary custody"},{"section":"305(b)","description":"Notification requirements to parent"},{"section":"306","description":"Reasonable efforts to prevent removal"},{"section":"309","description":"Placement preferences — relatives"},{"section":"311","description":"Release from custody — to parent or continued detention"},{"section":"313","description":"Filing petition within 48 hours if detained"}]', '["detention_report","JV_100","JV_101","protective_custody_warrant","social_worker_report","relative_placement_assessment","ICWA_inquiry"]', '["cps-dependency-family-reunification-audit"]', 'Juvenile Court / County CPS / Law Enforcement', 0, 1, datetime('now'), datetime('now'));

-- WIC 319 — Detention Hearing
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_069', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Welf. & Inst. Code § 319 (Detention Hearing)', 'WIC § 319', 'Detention Hearing — 48/72-Hour Judicial Review of Removal', 'Detention hearing must be held within 48 hours (72 hours if weekend/holiday) of removal. Court determines whether prima facie case for jurisdiction and whether continued detention is necessary. Court must order release unless substantial danger to child. Parent has right to counsel at detention. ICWA protections apply if Indian child.', '["Hearing within 48 hours of filing petition (72 if weekend/holiday)","Court makes prima facie finding on jurisdiction","Court determines whether continuance in home contrary to child welfare","Must release unless substantial danger and no reasonable means to protect without removal","Court must consider less restrictive alternatives","Parent has right to appointed counsel if indigent","Child has right to appointed counsel","ICWA active efforts and expert testimony requirements if Indian child","Court must make ICWA findings on record","Temporary visitation orders may be entered"]', '[{"section":"319(a)","description":"Timing — hearing within 48/72 hours"},{"section":"319(b)","description":"Prima facie case finding required"},{"section":"319(c)","description":"Findings for continued detention — substantial danger"},{"section":"319(d)","description":"Less restrictive alternatives must be considered"},{"section":"319(e)","description":"Right to counsel — parent and child"},{"section":"319(f)","description":"Visitation orders — liberal unless safety concern"},{"section":"319(h)","description":"ICWA — active efforts finding required"}]', '["detention_hearing_findings","JV_410","visitation_order","counsel_appointment","ICWA_findings","JV_412","prima_facie_order"]', '["cps-dependency-family-reunification-audit"]', 'Juvenile Court', 0, 1, datetime('now'), datetime('now'));

-- WIC 361 — Removal from Parent
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_070', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Welf. & Inst. Code § 361 (Removal — Dispositional Findings)', 'WIC § 361', 'Dispositional Removal — Clear and Convincing Evidence Standard', 'At disposition, court may remove child from parent only upon clear and convincing evidence of substantial danger to physical health, safety, protection, or well-being and no reasonable means to protect without removal. Reasonable efforts to prevent removal must be made. Case plan for reunification services must be ordered. Placement preferences: relative, NREFM, foster care.', '["Clear and convincing evidence required for removal (§ 361(c)(1))","Substantial danger to physical health, safety, protection, or well-being","No reasonable means to protect child without removal","Reasonable efforts to prevent or eliminate need for removal","Court must consider alternatives: in-home services, removal of offending parent","If removed, reunification services ordered (§ 361.5)","Case plan must be developed (§ 16501.1)","Placement preferences: relative → NREFM → foster care (§ 361.3)","ICWA: active efforts and qualified expert testimony required for Indian child","Court must state facts supporting removal on the record"]', '[{"section":"361(c)(1)","description":"Clear and convincing evidence — substantial danger, no reasonable means"},{"section":"361(c)(4)","description":"Offending parent removal as alternative"},{"section":"361(d)","description":"Court must state facts supporting removal on record"},{"section":"361.2","description":"Placement with noncustodial parent — presumptive right"},{"section":"361.3","description":"Relative placement preference"},{"section":"361.5","description":"Reunification services — 6-12 months depending on child age"}]', '["dispositional_order","JV_415","case_plan","reunification_services_order","ICWA_findings","relative_assessment","reasonable_efforts_finding"]', '["cps-dependency-family-reunification-audit"]', 'Juvenile Court / County CPS', 0, 1, datetime('now'), datetime('now'));

-- WIC 366.21/366.26 — Review and Permanency
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_071', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Welf. & Inst. Code §§ 366.21-366.26 (Review Hearings and Permanency Planning)', 'WIC §§ 366.21-366.26', 'Dependency Review Hearings and Permanency Planning — Timelines', 'Structured timeline for dependency proceedings. 6-month review (§ 366.21(e)): assess compliance with case plan. 12-month permanency hearing (§ 366.21(f)): return child or set § 366.26 hearing. 18-month review (§ 366.22): last chance for reunification. 366.26 hearing: select permanent plan — adoption (preferred), legal guardianship, or long-term foster care. Parental rights terminated if adoption selected.', '["6-month review: assess case plan compliance, reasonable services provided (§ 366.21(e))","12-month permanency hearing: return child or set .26 hearing (§ 366.21(f))","18-month review: final reunification opportunity (§ 366.22)","24-month review for certain cases under § 366.25","§ 366.26 hearing: select permanent plan","Permanent plan preference: adoption > guardianship > long-term foster care","If adoption, court terminates parental rights","Beneficial relationship exception — may not terminate if strong bond (§ 366.26(c)(1)(B)(i))","ASFA timelines: permanency decision within 12 months of entering foster care","Sibling group kept together when possible"]', '[{"section":"366.21(e)","description":"6-month review — services and compliance"},{"section":"366.21(f)","description":"12-month permanency hearing — return or set .26"},{"section":"366.22","description":"18-month review — final reunification chance"},{"section":"366.25","description":"24-month review — limited circumstances"},{"section":"366.26(b)","description":"Selection of permanent plan — adoption, guardianship, LTFC"},{"section":"366.26(c)(1)","description":"Termination of parental rights if adoption recommended"},{"section":"366.26(c)(1)(B)(i)","description":"Beneficial relationship exception — regular visitation and benefit"}]', '["6_month_review_report","12_month_permanency_report","18_month_review","366.26_report","adoption_assessment","guardianship_assessment","TPR_order","JV_320","case_plan_update"]', '["cps-dependency-family-reunification-audit"]', 'Juvenile Court / County CPS / CDSS', 0, 1, datetime('now'), datetime('now'));

-- ICWA
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_072', 'ADVOCIS', 'FEDERAL_STATUTE', 'US', '25 USC §§ 1901-1963 (Indian Child Welfare Act) / Cal. WIC §§ 224-224.6', 'ICWA / 25 USC §§ 1901-1963', 'Indian Child Welfare Act — Tribal Sovereignty and Placement Preferences', 'Federal law protecting Indian children, families, and tribal sovereignty in child custody proceedings. Requires notice to tribes, active efforts (not just reasonable efforts), qualified expert witness testimony before foster care placement. Placement preferences: extended family → tribal foster home → Indian foster home → approved institution. Haaland v. Brackeen (2023): ICWA upheld as constitutional.', '["ICWA inquiry required at outset of every dependency case (§ 224.2)","Notice to tribe within specified timeframes if child may be Indian child","Active efforts to prevent breakup of Indian family — more than reasonable efforts","Qualified expert witness testimony required before foster care placement","Placement preferences: (1) extended family, (2) tribal foster home, (3) Indian foster home, (4) approved institution","Transfer to tribal court on request unless good cause","Beyond a reasonable doubt for termination of parental rights","Clear and convincing evidence for foster care placement","Tribe has right to intervene at any point","Invalidation of proceedings if ICWA violated"]', '[{"section":"1901","description":"Congressional findings — Indian family integrity"},{"section":"1903","description":"Definitions — Indian child, Indian child custody proceeding"},{"section":"1911","description":"Tribal court jurisdiction — exclusive and concurrent"},{"section":"1912","description":"Notice, active efforts, qualified expert witness"},{"section":"1913","description":"Voluntary consent requirements — in writing, before judge"},{"section":"1914","description":"Invalidation of proceedings for ICWA violation"},{"section":"1915","description":"Placement preferences"},{"section":"WIC 224.2","description":"California ICWA inquiry requirements"}]', '["ICWA_notice","tribal_inquiry","ICWA_findings","JV_135","qualified_expert_testimony","active_efforts_finding","placement_preference_documentation","tribal_intervention"]', '["cps-dependency-family-reunification-audit"]', 'Tribal Courts / Juvenile Court / BIA', 0, 1, datetime('now'), datetime('now'));
